862	  //  스캐너가 nonStandard로 분리한 항목을 그 도구 열에 "비표준" 슬롯으로 얹는다(내용 비교 안 함).
863	  //  파일명(확장자 제거)을 이름 키로 삼아 같은 이름의 정식 행과 합류시킨다.
864	  for (const ns of disc.nonStandard) {
865	    const scope = ns.scope === 'project' ? ns.projectRoot : 'global';
866	    const nm = ns.file.replace(/\.[^.]+$/, '');
